PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT DISTINCT ?judge ?judgeLabel WHERE {
  wd:Q2872153 wdt:P5002 ?season .
  ?season wdt:P12484 ?judge .
  OPTIONAL {
    ?judge rdfs:label ?judgeLabel
    FILTER(LANG(?judgeLabel) = "en")
  }
}
